  // browser, sandboxed process — the URL in the message below is the
  // fallback the user opens manually.
  void open(authUrl).catch(() => {});

  return {
    success: true,
    message:
      "FamilySearch login started. A browser tab should have opened for you " +
      "to sign in.\n\n" +
