export const personReadToolSchema = {
  name: "person_read",
  description:
    "Read person data from the FamilySearch Family Tree. " +
    "Returns simplified GEDCOMX (persons, relationships, sources). " +
    "Set relatives=true to include parents, spouses, and children. " +
