// FamilySearch Read Ancestry API response + tool I/O types.
// GET https://api.familysearch.org/platform/tree/ancestry
//
// Only the fields the tool reads directly are declared with precision; the
// names/gender/facts/sources/identifiers are otherwise passed straight to
// `toSimplified` (cast to GedcomX), which reads the full runtime structure.

import type { SimplifiedPerson, SimplifiedRelationship } from "./gedcomx.js";

// ─── Upstream (FS) response shapes ──────────────────────────────────────────

export interface FSAncestryDisplay {
  // Ahnentafel position — a STRING ("1", "2", "1-S"); the only field that
  // encodes the pedigree. `toSimplified` ignores the whole display block, so
  // the tool re-attaches this onto each converted person.
  ascendancyNumber?: string;
  name?: string;
  lifespan?: string;
}

export interface FSAncestryPerson {
  id?: string;
  living?: boolean;
  gender?: { type?: string };
  names?: unknown[];
  facts?: unknown[];
  sources?: unknown[];
  identifiers?: Record<string, string[]>;
  display?: FSAncestryDisplay;
}

export interface FSAncestryResponse {
  persons?: FSAncestryPerson[];
  relationships?: unknown[];
}

// GET /platform/users/current — only the field the self-default reads.
export interface FSCurrentUserResponse {
  users?: Array<{ personId?: string }>;
}

// ─── Tool I/O ───────────────────────────────────────────────────────────────

export interface PersonAncestorsInput {
  // Optional: when omitted/empty, the tool resolves the logged-in user's
  // own tree person (returns the user and their ancestors).
  personId?: string;
  generations?: number;
  spouse?: string;
  personDetails?: boolean;
  marriageDetails?: boolean;
  descendants?: boolean;
}

// A simplified person plus the one ancestry-specific field. `ascendancyNumber`
// has no slot in standard simplified GedcomX, so it is added here.
export interface AncestorPerson extends SimplifiedPerson {
  ascendancyNumber: string;
}

// The pedigree as a simplified GedcomX graph, returned directly (no envelope),
// the same shape `person_read` returns. `relationships` is present only when
// `marriageDetails` is requested.
export interface PersonAncestorsResult {
  persons: AncestorPerson[];
  relationships?: SimplifiedRelationship[];
}

// person_read tool I/O types and FS-extended GEDCOMX response types.
// See docs/specs/person-read-tool-spec.md.
//
// The person_read tool returns *simplified* GEDCOMX (per the shared
// docs/specs/simplified-gedcomx-spec.md), but the FamilySearch API
// returns FS-extended GEDCOMX which has a few fields beyond what the
// shared `GedcomX` type models — notably `person.living` and the
// `childAndParentsRelationships[]` array. Those FS-specific shapes
// live here.

import type {
  GedcomXFact,
  GedcomXPerson,
  GedcomXSourceDescription,
} from "./gedcomx.js";

// ─── Tool I/O ─────────────────────────────────────────────────────────────

export interface PersonReadToolInput {
  personId: string;
  relatives?: boolean;
  sourceDescriptions?: boolean;
}

export interface TreeName {
  given: string;
  surname: string;
  prefix?: string;
  suffix?: string;
}

export interface TreeFact {
  id?: string;
  type: string;
  primary?: boolean;
  date?: string;
  standard_date?: string;
  place?: string;
  value?: string;
}

export interface TreePerson {
  id: string;
  gender: string;
  living: boolean;
  names: TreeName[];
  facts?: TreeFact[];
}

export interface TreeRelationship {
  type: "ParentChild" | "Couple";
  parent?: string;
  child?: string;
  subtype?: string;
  person1?: string;
  person2?: string;
  facts?: TreeFact[];
}

export interface TreeSource {
  id: string;
  title: string;
  citation?: string;
  url?: string;
  notes?: string[];
}

export interface PersonReadResult {
  persons: TreePerson[];
  relationships: TreeRelationship[];
  sources: TreeSource[];
}

// ─── FS-extended GEDCOMX (raw API response) ───────────────────────────────

export interface FSPerson extends GedcomXPerson {
  living?: boolean;
}

export interface FSFact extends GedcomXFact {
  value?: string;
}

export interface FSResourceRef {
  resource?: string;
  resourceId?: string;
}

export interface FSChildAndParentsRelationship {
  id?: string;
  parent1?: FSResourceRef;
  parent2?: FSResourceRef;
  child?: FSResourceRef;
  parent1Facts?: FSFact[];
  parent2Facts?: FSFact[];
}

// FS relationship entries in `relationships[]` (couples, bare
// ParentChild). Unlike standard GEDCOMX — whose person refs expose only
// `resource` — the FS tree API returns `resourceId`-only refs here, so
// `person1`/`person2` must reuse `FSResourceRef`.
export interface FSRelationship {
  id?: string;
  type?: string;
  person1?: FSResourceRef;
  person2?: FSResourceRef;
  facts?: FSFact[];
}

export interface FSSourceDescription extends GedcomXSourceDescription {
  notes?: Array<{ value?: string }>;
  resourceType?: string;
}

export interface FSTreeResponse {
  persons?: FSPerson[];
  relationships?: FSRelationship[];
  childAndParentsRelationships?: FSChildAndParentsRelationship[];
  sourceDescriptions?: FSSourceDescription[];
}

// FamilySearch Tree Search API response + tool I/O types
// GET https://api.familysearch.org/platform/tree/search

import type { SimplifiedGedcomX } from "./gedcomx.js";

// ─── Upstream (FS) response shapes ──────────────────────────────────────
// Only the fields the tool reads directly are declared. The matched person
// is otherwise passed straight to `toSimplified` (cast to GedcomX), which
// reads the full runtime structure (names, facts, gender, identifiers).

export interface FSTreeSearchPerson {
  id?: string;
  identifiers?: Record<string, string[]>;
}

export interface FSTreeSearchGedcomx {
  id?: string;
  description?: string;
  persons?: FSTreeSearchPerson[];
  relationships?: unknown[];
}

export interface FSTreeSearchEntry {
  id?: string;
  title?: string;
  score?: number;
  confidence?: number;
  content?: { gedcomx?: FSTreeSearchGedcomx };
}

export interface FSTreeSearchResponse {
  results?: number;
  index?: number;
  links?: { next?: { href?: string } };
  entries?: FSTreeSearchEntry[];
}

// ─── Tool I/O ───────────────────────────────────────────────────────────

export interface PersonSearchInput {
  givenName?: string;
  surname?: string;
  sex?: string;
  givenNameExact?: boolean;
  surnameExact?: boolean;

  birthYearFrom?: number;
  birthYearTo?: number;
  birthYearExact?: boolean;
  birthPlace?: string;
  birthPlaceExact?: boolean;

  deathYearFrom?: number;
  deathYearTo?: number;
  deathYearExact?: boolean;
  deathPlace?: string;
  deathPlaceExact?: boolean;

  marriageYearFrom?: number;
  marriageYearTo?: number;
  marriageYearExact?: boolean;
  marriagePlace?: string;
  marriagePlaceExact?: boolean;

  residenceYearFrom?: number;
  residenceYearTo?: number;
  residenceYearExact?: boolean;
  residencePlace?: string;
  residencePlaceExact?: boolean;

  spouseGivenName?: string;
  spouseSurname?: string;
  spouseGivenNameExact?: boolean;
  spouseSurnameExact?: boolean;

  fatherGivenName?: string;
  fatherSurname?: string;
  fatherGivenNameExact?: boolean;
  fatherSurnameExact?: boolean;
  fatherBirthPlace?: string;
  fatherBirthPlaceExact?: boolean;

  motherGivenName?: string;
  motherSurname?: string;
  motherGivenNameExact?: boolean;
  motherSurnameExact?: boolean;
  motherBirthPlace?: string;
  motherBirthPlaceExact?: boolean;

  parentGivenName?: string;
  parentSurname?: string;
  parentGivenNameExact?: boolean;
  parentSurnameExact?: boolean;
  parentBirthPlace?: string;
  parentBirthPlaceExact?: boolean;

  count?: number;
  offset?: number;
}

export interface PersonSearchResult {
  // Bare Family-Tree person ID (e.g. "LZJW-C31"); the handle for person_read.
  personId: string;
  // Search-relevance metadata — not part of any GedcomX.
  score?: number;
  confidence?: number;
  // The matched person only (id, ark, gender, names, facts). No relatives.
  gedcomx: SimplifiedGedcomX;
}

export interface PersonSearchToolResponse {
  query: Partial<PersonSearchInput>;
  totalMatches: number;
  paginationCappedAt: number;
  returned: number;
  offset: number;
  hasMore: boolean;
  results: PersonSearchResult[];
}

// Types for the `person_warnings` MCP tool.
// See `docs/specs/person-warnings-tool-spec.md`.

export interface PersonWarningsInput {
  projectPath: string;
  personId: string;
}

export interface PersonWarning {
  scoreType: string;
  issueType: string;
  severity: "error" | "warning";
  personId: string;
  personName: string;
  message: string;
  /**
   * Optional. Java's MobWarnings emits only the warning tag (`issueType`) —
   * specific facts aren't carried through. Our TS port may attach the
   * contributing facts when they're cheaply retrievable, for UI highlighting.
   */
  factIds?: string[];
  relatedPersonId?: string;
}

export interface PersonWarningsResult {
  warningCount: number;
  warnings: PersonWarning[];
}

