// record_read tool I/O types and FS recapi response types.
//
// The tool accepts a FamilySearch historical record ID (either a full ARK like
// `ark:/61903/1:1:QVS9-DHDB` or a bare entity ID like `QVS9-DHDB`), fetches
// the record from the recapi endpoint, and returns simplified GEDCOMX.

import type { SimplifiedGedcomX } from "./gedcomx.js";

// ─── Tool I/O ─────────────────────────────────────────────────────────────

export interface RecordReadInput {
  recordId: string;
}

// The tool returns simplified GEDCOMX directly.
export type RecordReadResult = SimplifiedGedcomX;

// ─── FS recapi response (raw API) ─────────────────────────────────────────
//
// The recapi endpoint returns a GedcomX document. We reuse the shared
// `GedcomX` type from `./gedcomx.ts` for the actual parse; this file only
// declares the thin wrapper the endpoint places around it.

export interface FSRecordResponse {
  // The recapi envelope nests the GedcomX payload under a top-level key.
  // We treat the entire response as a GedcomX document since the recapi
  // format is standard GedcomX JSON — persons, relationships, and
  // sourceDescriptions live at the top level.
  persons?: unknown[];
  relationships?: unknown[];
  sourceDescriptions?: unknown[];
  places?: unknown[];
}

// FamilySearch Search API Response Types
// GET https://www.familysearch.org/service/search/hr/v2/personas

import type { SimplifiedGedcomX } from "./gedcomx.js";

export interface FSDisplay {
  name?: string;
  gender?: string;
  birthDate?: string;
  birthPlace?: string;
  deathDate?: string;
  deathPlace?: string;
  role?: string;
}

export interface FSFact {
  type: string;
  date?: { original?: string };
  place?: { original?: string };
  value?: string;
}

export interface FSNameForm {
  fullText?: string;
}

export interface FSName {
  nameForms?: FSNameForm[];
}

export interface FSPerson {
  principal?: boolean;
  id?: string;
  display?: FSDisplay;
  names?: FSName[];
  gender?: { type?: string };
  facts?: FSFact[];
  identifiers?: Record<string, string[]>;
}

export interface FSSourceTitle {
  value?: string;
}

export interface FSSourceDescription {
  resourceType?: string;
  about?: string;
  titles?: FSSourceTitle[];
  identifiers?: Record<string, string[]>;
}

export interface FSGedcomx {
  persons?: FSPerson[];
  sourceDescriptions?: FSSourceDescription[];
}

export interface FSEntryContent {
  gedcomx?: FSGedcomx;
}

export interface FSHint {
  id?: string;
  stars?: number;
}

export interface FSSearchEntry {
  id?: string;
  score?: number;
  confidence?: number;
  hints?: FSHint[];
  content?: FSEntryContent;
}

export interface FSLink {
  href?: string;
}

export interface FSSearchResponse {
  results?: number;
  index?: number;
  links?: { next?: FSLink };
  entries?: FSSearchEntry[];
}

// Tool I/O Types

export type Sex = "Male" | "Female" | "Unknown";

export type MaritalStatus = "Married" | "Single" | "Divorced" | "Widowed";

export type RecordType =
  | "birth"
  | "marriage"
  | "death"
  | "census"
  | "immigration"
  | "military"
  | "probate"
  | "other";

export interface RecordSearchInput {
  surname?: string;
  givenName?: string;
  surnameAlt?: string;
  givenNameAlt?: string;
  sex?: string;
  surnameExact?: boolean;
  givenNameExact?: boolean;

  birthYearFrom?: number;
  birthYearTo?: number;
  birthYearExact?: boolean;
  birthPlace?: string;
  birthPlaceExact?: boolean;

  deathYearFrom?: number;
  deathYearTo?: number;
  deathYearExact?: boolean;
  deathPlace?: string;
  deathPlaceExact?: boolean;

  marriageYearFrom?: number;
  marriageYearTo?: number;
  marriageYearExact?: boolean;
  marriagePlace?: string;
  marriagePlaceExact?: boolean;

  residenceYearFrom?: number;
  residenceYearTo?: number;
  residenceYearExact?: boolean;
  residencePlace?: string;
  residencePlaceExact?: boolean;

  anyYearFrom?: number;
  anyYearTo?: number;
  anyYearExact?: boolean;
  anyPlace?: string;
  anyPlaceExact?: boolean;

  spouseGivenName?: string;
  spouseSurname?: string;
  spouseGivenNameExact?: boolean;
  spouseSurnameExact?: boolean;
  fatherGivenName?: string;
  fatherSurname?: string;
  fatherGivenNameExact?: boolean;
  fatherSurnameExact?: boolean;
  motherGivenName?: string;
  motherSurname?: string;
  motherGivenNameExact?: boolean;
  motherSurnameExact?: boolean;
  parentGivenName?: string;
  parentSurname?: string;
  parentGivenNameExact?: boolean;
  parentSurnameExact?: boolean;
  otherGivenName?: string;
  otherSurname?: string;
  otherGivenNameExact?: boolean;
  otherSurnameExact?: boolean;

  collectionId?: string;
  imageGroupNumber?: string;
  recordCountry?: string;
  recordSubdivision?: string;
  recordType?: string;
  maritalStatus?: string;
